# A minimal MCP server in Python using the mcp SDK
# pip install mcp

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp import types
import asyncio

app = Server("my-custom-server")

@app.list_tools()
async def list_tools() -> list[types.Tool]:
    return [
        types.Tool(
            name="get_weather",
            description="Get current weather for a city.",
            inputSchema={
                "type": "object",
                "properties": {
                    "city": {"type": "string", "description": "City name"}
                },
                "required": ["city"],
            },
        )
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict) -> list[types.TextContent]:
    if name == "get_weather":
        city = arguments["city"]
        # In a real server, call a weather API here
        return [types.TextContent(type="text", text=f"Weather in {city}: 22°C, partly cloudy")]
    raise ValueError(f"Unknown tool: {name}")

async def main():
    async with stdio_server() as (read, write):
        await app.run(read, write, app.create_initialization_options())

if __name__ == "__main__":
    asyncio.run(main())

from mcp import ClientSession
from mcp.types import CallToolResult

async def safe_call_tool(
    session: ClientSession, name: str, args: dict
) -> str | None:
    """Call a tool and return text content, or None on error."""
    try:
        result: CallToolResult = await session.call_tool(name, args)
    except Exception as exc:
        # Transport error (server crashed, process killed, etc.)
        return f"Transport error calling {name}: {exc}"

    if result.isError:
        # Application-level error returned by the server
        error_text = "\n".join(
            c.text for c in result.content if hasattr(c, "text")
        )
        return f"Tool error: {error_text}"

    return "\n".join(
        c.text for c in result.content if hasattr(c, "text")
    )
